#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int max(int a, int b) { return (a > b) ? a : b; }
int min(int a, int b) { return (a < b) ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* S = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &S[i]);
        }
        long long ans = 0;
        for (int mask = 1; mask < (1 << N); mask++) {
            int max_val = -1, min_val = 1000000001;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    max_val = max(max_val, S[i]);
                    min_val = min(min_val, S[i]);
                }
            }
            if (max_val != -1) {
                ans = (ans + max_val - min_val) % MOD;
            }
        }
        printf("%lld\n", ans);
        free(S);
    }
    return 0;
}

